import React, { useState } from 'react';
import { supabase } from '../supabaseClient';
import { useTranslation } from 'react-i18next';
import i18n from '../i18n';
import {
    TextField,
    Button,
    FormControl,
    InputLabel,
    Select,
    MenuItem,
    Paper,
    Table,
    TableBody,
    TableCell,
    TableContainer,
    TableHead,
    TableRow,
    Alert,
    CircularProgress,
    Typography,
} from '@mui/material';
import { DateRangePicker } from 'react-date-range';
import 'react-date-range/dist/styles.css';
import 'react-date-range/dist/theme/default.css';
import { format } from 'date-fns';
import { ko } from 'date-fns/locale';

function MoldSearch() {
    const [searchMoldId, setSearchMoldId] = useState('');
    const [moldIdPrefix1, setMoldIdPrefix1] = useState('');
    const [moldIdPrefix2, setMoldIdPrefix2] = useState('');
    const [moldIdSuffix, setMoldIdSuffix] = useState('');
    const [status, setStatus] = useState('');
    const [statusDate, setStatusDate] = useState('');
    const [statusDateRange, setStatusDateRange] = useState([
        {
            startDate: null,
            endDate: null,
            key: 'selection',
        },
    ]);
    const [inspector, setInspector] = useState('');
    const [moldCount, setMoldCount] = useState('');
    const [inspectionStatus, setInspectionStatus] = useState('');
    const [searchResults, setSearchResults] = useState([]);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState(null);
    const { t } = useTranslation();
    const [isDateRangeOpen, setDateRangeOpen] = useState(false);

    const changeLanguage = (lang) => {
        i18n.changeLanguage(lang);
        localStorage.setItem('language', lang);
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        setLoading(true);
        setError(null);

        let composedMoldId = '';
        if (moldIdPrefix1) {
            composedMoldId += moldIdPrefix1;
        }
        if (moldIdPrefix2) {
            composedMoldId += (composedMoldId ? '-' : '') + moldIdPrefix2;
        }
        if (moldIdSuffix) {
            composedMoldId += (composedMoldId ? '-' : '') + moldIdSuffix;
        }

        const query = {};
        if (status) query.status = status;

        // 날짜 범위 처리
        if (statusDateRange[0].startDate) {
            const startDate = statusDateRange[0].startDate.toISOString();
            const endDate = statusDateRange[0].endDate
                ? new Date(statusDateRange[0].endDate.getTime() + 86399999).toISOString()
                : new Date(statusDateRange[0].startDate.getTime() + 86399999).toISOString();  // endDate가 null일 경우 startDate와 동일한 날짜로 처리

            query.status_date = `gte.${startDate},lte.${endDate}`;
        } else if (statusDate) {
            query.status_date = statusDate;
        }

        if (inspector) query.inspector = inspector;
        if (moldCount !== null && moldCount !== undefined && moldCount !== '') query.mold_count = moldCount;
        if (inspectionStatus) query.inspection_status = inspectionStatus;

        try {
            let supabaseQuery = supabase.from('molds').select('*');

            // 검색어 있을경우
            if (searchMoldId) {
                supabaseQuery = supabaseQuery.ilike('mold_id', `%${searchMoldId}%`);
            }

            // 조합된 Mold ID로 검색 (prefix, suffix)
            if (composedMoldId) {
                supabaseQuery = supabaseQuery.ilike('mold_id', `%${composedMoldId}%`);
            }

            // 나머지 조건
            supabaseQuery = supabaseQuery.match(
                Object.keys(query).reduce((obj, key) => {
                    if (key !== 'status_date' && query[key] !== null && query[key] !== undefined && query[key] !== '') {
                        obj[key] = query[key];
                    }
                    return obj;
                }, {})
            );

             // 날짜 필터
            supabaseQuery = supabaseQuery.filter(
                'status_date',
                query.status_date ? query.status_date : '',
                query.status_date ? true : false
            );

            const { data, error: fetchError } = await supabaseQuery;

            if (fetchError) {
                throw fetchError;
            }
            setSearchResults(data);
        } catch (err) {
            setError(err.message);
        } finally {
            setLoading(false);
        }
    };

    const handleGoBack = () => {
        window.history.back();
    };

    const prefix1Options = [
        { value: '', label: t('Select') },
        { value: 'MEB-', label: 'MEB-' },
        { value: 'E603C-', label: 'E603C-' },
    ];

    const prefix2Options = [
        { value: '', label: t('Select') },
        { value: 'ANM', label: 'ANM' },
        { value: 'CNM', label: 'CNM' },
    ];

    const inspectionStatusOptions = [
        { value: '', label: t('All') },
        { value: '양호', label: t('Good') },
        { value: '불량', label: t('Bad') },
    ];

    return (
        <div>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '10px' }}>
                <Typography variant="h5">{t('Mold Search')}</Typography>
                <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
                    <Select value={i18n.language} onChange={(e) => changeLanguage(e.target.value)}>
                        <MenuItem value="en">English</MenuItem>
                        <MenuItem value="ko">한국어</MenuItem>
                    </Select>
                    <Button variant="outlined" onClick={handleGoBack}>
                        {t('Back')}
                    </Button>
                </div>
            </div>
            <form onSubmit={handleSubmit}>
                <TextField
                    label={t('Mold ID')}
                    value={searchMoldId}
                    onChange={(e) => setSearchMoldId(e.target.value)}
                    fullWidth
                    margin="normal"
                    style={{ marginBottom: '16px' }}
                />
                <div style={{ display: 'flex', gap: '10px', marginBottom: '16px', alignItems: 'center' }}>
                    <FormControl>
                        <InputLabel id="mold-id-prefix1-label">{t('Prefix 1')}</InputLabel>
                        <Select
                            labelId="mold-id-prefix1-label"
                            id="moldIdPrefix1"
                            value={moldIdPrefix1}
                            onChange={(e) => setMoldIdPrefix1(e.target.value)}
                            label={t('Prefix 1')}
                        >
                            {prefix1Options.map((option) => (
                                <MenuItem key={option.value} value={option.value}>
                                    {option.label}
                                </MenuItem>
                            ))}
                        </Select>
                    </FormControl>
                    <span>-</span>
                    <FormControl>
                        <InputLabel id="mold-id-prefix2-label">{t('Prefix 2')}</InputLabel>
                        <Select
                            labelId="mold-id-prefix2-label"
                            id="moldIdPrefix2"
                            value={moldIdPrefix2}
                            onChange={(e) => setMoldIdPrefix2(e.target.value)}
                            label={t('Prefix 2')}
                        >
                            {prefix2Options.map((option) => (
                                <MenuItem key={option.value} value={option.value}>
                                    {option.label}
                                </MenuItem>
                            ))}
                        </Select>
                    </FormControl>
                    <span>-</span>
                    <TextField
                        label={t('Suffix')}
                        value={moldIdSuffix}
                        onChange={(e) => setMoldIdSuffix(e.target.value)}
                        style={{ flexGrow: 1 }}
                    />
                </div>
                <TextField
                    label={t('Status')}
                    value={status}
                    onChange={(e) => setStatus(e.target.value)}
                    fullWidth
                    margin="normal"
                    style={{ marginBottom: '16px' }}
                />
                <div style={{ marginBottom: '16px' }}>
                    <InputLabel>{t('Status Date/Time')}</InputLabel>
                    <div style={{ display: 'flex', gap: '10px', alignItems: 'center' }}>
                        <Button
                            variant="outlined"
                            onClick={() => setDateRangeOpen(!isDateRangeOpen)}
                        >
                            {statusDateRange[0].startDate
                                ? statusDateRange[0].endDate
                                    ? `${format(statusDateRange[0].startDate, 'yyyy-MM-dd', { locale: ko })} - ${format(
                                        statusDateRange[0].endDate,
                                        'yyyy-MM-dd',
                                        { locale: ko }
                                    )}`
                                    : format(statusDateRange[0].startDate, 'yyyy-MM-dd', { locale: ko })
                                : t('Select Date Range')}
                        </Button>
                        {isDateRangeOpen && (
                            <div style={{ position: 'absolute', zIndex: 1000 }}>
                                 <DateRangePicker
                                    onChange={(item) => setStatusDateRange([item.selection])}
                                    showSelectionPreview={true}
                                    moveRangeOnFirstSelection={false}
                                    ranges={statusDateRange}
                                    locale={ko}
                                    rangeColors={['#3b82f6']}
                                />
                            </div>
                        )}
                         <TextField
                            type="datetime-local"
                            value={statusDate}
                            onChange={(e) => setStatusDate(e.target.value)}
                            InputLabelProps={{
                                shrink: true,
                            }}
                            style={{ width: '200px' }}
                        />
                    </div>
                </div>

                <TextField
                    label={t('Inspector')}
                    value={inspector}
                    onChange={(e) => setInspector(e.target.value)}
                    fullWidth
                    margin="normal"
                    style={{ marginBottom: '16px' }}
                />
                <TextField
                    label={t('Mold Count')}
                    type="number"
                    value={moldCount}
                    onChange={(e) => setMoldCount(e.target.value)}
                    fullWidth
                    margin="normal"
                    style={{ marginBottom: '16px' }}
                />
                <FormControl fullWidth margin="normal" style={{ marginBottom: '16px' }}>
                    <InputLabel id="inspection-status-label">{t('Inspection Status')}</InputLabel>
                    <Select
                        labelId="inspection-status-label"
                        id="inspectionStatus"
                        value={inspectionStatus}
                        onChange={(e) => setInspectionStatus(e.target.value)}
                        label={t('Inspection Status')}
                    >
                        {inspectionStatusOptions.map((option) => (
                            <MenuItem key={option.value} value={option.value}>
                                {option.label}
                            </MenuItem>
                        ))}
                    </Select>
                </FormControl>
                <Button type="submit" variant="contained" color="primary">
                    {t('Search')}
                </Button>
            </form>

            {loading && <CircularProgress />}
            {error && <Alert severity="error">{error}</Alert>}

            {searchResults.length > 0 && (
                <Paper sx={{ mt: 3 }}>
                    <TableContainer>
                        <Table>
                            <TableHead>
                                <TableRow>
                                    <TableCell>{t('ID')}</TableCell>
                                    <TableCell>{t('Mold ID')}</TableCell>
                                    <TableCell>{t('Status')}</TableCell>
                                    <TableCell>{t('Status Date')}</TableCell>
                                    <TableCell>{t('Inspection Status')}</TableCell>
                                    <TableCell>{t('Inspector')}</TableCell>
                                    <TableCell>{t('Mold Count')}</TableCell>
                                </TableRow>
                            </TableHead>
                            <TableBody>
                                {searchResults.map((mold) => (
                                    <TableRow key={mold.id}>
                                        <TableCell>{mold.id}</TableCell>
                                        <TableCell>{mold.mold_id}</TableCell>
                                        <TableCell>{mold.status}</TableCell>
                                        <TableCell>{mold.status_date}</TableCell>
                                        <TableCell>{mold.inspection_status}</TableCell>
                                        <TableCell>{mold.inspector}</TableCell>
                                        <TableCell>{mold.mold_count}</TableCell>
                                    </TableRow>
                                ))}
                            </TableBody>
                        </Table>
                    </TableContainer>
                </Paper>
            )}
             {searchResults.length === 0 && !loading && !error && (
                <p>{t('No search results.')}</p>
            )}
        </div>
    );
}

export default MoldSearch;

